class Solution:
    def uniqueOccurrences(self, arr):
        counts = []
        for v in set(arr):
            counts.append(sum(1 for x in arr if x == v))
        for i in range(len(counts)):
            for j in range(i + 1, len(counts)):
                if counts[i] == counts[j]:
                    return False
        return True

